properties.entry:

TO_HEX(
	SHA256(
		CONCAT(projectId, '#', dataSourceId, '#', columnId, '#', classPK)
	)
) AS sha256HexId


MERGE INTO
	`{replicaTable}` AS {replicaTableAlias}
USING
	{stagingTableSQL} AS {stagingTableAlias}
ON
	{joinConditions}
WHEN MATCHED THEN
	{updateSQL}
WHEN NOT MATCHED BY TARGET THEN
	{insertSQL}


TO_HEX(
	SHA256(
		CONCAT(projectId, '#', dataSourceId, '#', classPK)
	)
) AS sha256HexId


(
	SELECT
		ARRAY (
			SELECT
				SAFE_CAST(number AS INT64)
			FROM
				UNNEST(arrayField.{fieldName}) AS number
		)
	FROM (
		SELECT (
			SELECT
				JSON_EXTRACT_ARRAY(value)
			FROM
				UNNEST(fields)
			WHERE
				name = '{fieldName}'
		) {fieldName}
	) arrayField
) {fieldName}
